oxy_webhelp_navlinks = {"microsoft_entra_id-d27248e45071":{"topics":[{"title":"Known limitations for Microsoft Entra ID on <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">Microsoft Entra ID on <span class=\"ph\">RSC<\/span> includes some known limitations for         recovering groups, users, relationships, and Microsoft Entra ID properties.<\/p>","href":"saas\/ms_entra_id_known_limits_rsc.html","attributes":{"data-id":"ms_entra_id_known_limits_rsc"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_known_limits_rsc-d27248e45084","topics":[]},{"title":"Non-recovery of soft-deleted objects by <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> does not recover higher-privileged, soft-deleted Microsoft Entra         ID user or group objects. Instead, <span class=\"ph\">RSC<\/span> creates new objects, leaving the         soft-deleted ones in the Microsoft Recycle Bin.<\/p>","href":"saas\/ms_entra_id_non_recov_soft_del_obj_rsc.html","attributes":{"data-id":"ms_entra_id_non_recov_soft_del_obj_rsc"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_non_recov_soft_del_obj_rsc-d27248e45100","topics":[]},{"title":"Microsoft Entra ID just-in-time access","shortdesc":"<p class=\"shortdesc\">Just-in-time access for Microsoft Entra ID separates read and write access to align         with the principle of least privilege, ensuring that critical write permissions are active         only during necessary recovery operations. Just-in-time access is available for Microsoft         Entra ID domains using OAuth authentication.<\/p>","href":"saas\/ms_entra_id_jit_access.html","attributes":{"data-id":"ms_entra_id_jit_access"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_jit_access-d27248e45118","topics":[]},{"title":"Adding a Microsoft Entra ID directory with OAuth","shortdesc":"<p class=\"shortdesc\">Add a Microsoft Entra ID directory as a protected workload using OAuth for         authentication.<\/p>","href":"saas\/adding_entra_id_with_oauth.html","attributes":{"data-id":"adding_entra_id_with_oauth"},"menu":{"hasChildren":false},"tocID":"adding_entra_id_with_oauth-d27248e45129","topics":[]},{"title":"Adding a Microsoft Entra ID directory without OAuth","shortdesc":"<p class=\"shortdesc\">Add a Microsoft Entra ID directory as a protected workload without OAuth, using your         existing Microsoft Entra ID domain application registration for authentication.<\/p>","href":"saas\/adding_entra_id_without_oauth.html","attributes":{"data-id":"adding_entra_id_without_oauth"},"menu":{"hasChildren":false},"tocID":"adding_entra_id_without_oauth-d27248e45140","next":"adding_entra_id_without_oauth-d27248e45140"},{"title":"Editing a Microsoft Entra ID domain","shortdesc":"<p class=\"shortdesc\">Edit the configuration for Microsoft Entra ID domains added to <span class=\"ph\">RSC<\/span>         .<\/p>","href":"saas\/ms_entra_id_editing_domain.html","attributes":{"data-id":"ms_entra_id_editing_domain"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_editing_domain-d27248e45164","topics":[]},{"title":"Deleting a Microsoft Entra ID domain","shortdesc":"<p class=\"shortdesc\">Delete a Microsoft Entra ID domain from a directory when the domain no longer         requires protection.<\/p>","href":"saas\/ms_entra_id_deleting_domains_directories.html","attributes":{"data-id":"ms_entra_id_deleting_domains_directories"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_deleting_domains_directories-d27248e45178","topics":[]},{"title":"Protecting Microsoft Entra ID","shortdesc":"<p class=\"shortdesc\">Choose a data protection policy for a Microsoft Entra ID directory.<\/p>","href":"saas\/ms_entra_id_protecting.html","attributes":{"data-id":"ms_entra_id_protecting"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_protecting-d27248e45189","topics":[]},{"title":"Taking on-demand snapshots of Microsoft Entra ID","shortdesc":"<p class=\"shortdesc\">Take on-demand snapshots of Microsoft Entra ID protectable objects in addition to the         policy-based snapshots provided by the SLA Domain.<\/p>","href":"saas\/ms_entra_id_taking_ods.html","attributes":{"data-id":"ms_entra_id_taking_ods"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_taking_ods-d27248e45200","topics":[]},{"title":"Deleting a Microsoft Entra ID snapshot","shortdesc":"<p class=\"shortdesc\">Delete a Microsoft Entra ID snapshot that has the Forever retention policy         assigned.<\/p>","href":"saas\/ms_entra_id_deleting_snapshot.html","attributes":{"data-id":"ms_entra_id_deleting_snapshot"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_deleting_snapshot-d27248e45211","topics":[]},{"title":"Viewing Microsoft Entra ID directories","shortdesc":"<p class=\"shortdesc\">View details for the Microsoft Entra ID directories.<\/p>","href":"saas\/ms_entra_id_viewing_directories.html","attributes":{"data-id":"ms_entra_id_viewing_directories"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_viewing_directories-d27248e45223","next":"ms_entra_id_viewing_directories-d27248e45223"},{"title":"Microsoft Entra ID object and relationship recovery","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> recovers various Microsoft Entra ID objects and object         relationships, including users, groups, roles, enterprise apps, and app         registrations.<\/p>","href":"saas\/ms_entra_id_obj_relationship_recovery.html","attributes":{"data-id":"ms_entra_id_obj_relationship_recovery"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_obj_relationship_recovery-d27248e45245","next":"ms_entra_id_obj_relationship_recovery-d27248e45245"},{"title":"Microsoft Entra ID cross-tenant recovery","shortdesc":"<p class=\"shortdesc\">Microsoft Entra ID cross-tenant recovery restores directory data from a source tenant         to a separate, distinct target tenant to ensure business continuity during catastrophic         events.<\/p>","href":"saas\/ms_entra_id_ctr.html","attributes":{"data-id":"ms_entra_id_ctr"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_ctr-d27248e45362","next":"ms_entra_id_ctr-d27248e45362"},{"title":"Microsoft Intune protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects critical Microsoft Intune objects to maintain a         resilient identity and endpoint posture.<\/p>","href":"saas\/ms_entra_id_protect_microsoft_intune.html","attributes":{"data-id":"ms_entra_id_protect_microsoft_intune"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_protect_microsoft_intune-d27248e45417","next":"ms_entra_id_protect_microsoft_intune-d27248e45417"},{"title":"Microsoft Entra ID user object attribute recovery","shortdesc":"<p class=\"shortdesc\">Attribute recovery for a Microsoft Entra ID user object selectively restores specific         attributes that were maliciously or accidentally altered without performing a full object         restore. You can compare user object attributes from a snapshot against live data and         recover only the changed attributes.<\/p>","href":"saas\/ms_entra_id_user_obj_attr_recov.html","attributes":{"data-id":"ms_entra_id_user_obj_attr_recov"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_user_obj_attr_recov-d27248e45468","next":"ms_entra_id_user_obj_attr_recov-d27248e45468"},{"title":"Microsoft Entra ID object recovery across snapshots","shortdesc":"<p class=\"shortdesc\">With <span class=\"ph\">RSC<\/span>, you can search Microsoft Entra ID user, groups, and roles         objects for recovery across different snapshots. This functionality enables recovery of         objects and relationships from a specific date and time.<\/p>","href":"saas\/ms_entra_id_obj_recov_across_snapshots.html","attributes":{"data-id":"ms_entra_id_obj_recov_across_snapshots"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_obj_recov_across_snapshots-d27248e45501","next":"ms_entra_id_obj_recov_across_snapshots-d27248e45501"},{"title":"Microsoft Entra ID Conditional Access recovery","shortdesc":"<p class=\"shortdesc\">For Microsoft Entra ID directories that support Conditional Access, <span class=\"ph\">RSC<\/span> can protect Microsoft Entra ID Conditional Access objects and relationships.<\/p>","href":"saas\/ms_entra_id_conditional_access_recovery.html","attributes":{"data-id":"ms_entra_id_conditional_access_recovery"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_conditional_access_recovery-d27248e45548","next":"ms_entra_id_conditional_access_recovery-d27248e45548"},{"title":"Recovery in a hybrid identity environment","shortdesc":"<p class=\"shortdesc\">In a hybrid Microsoft Entra ID and Active Directory environment on <span class=\"ph\">RSC<\/span>, you can view Active Directory group and user assignments synced from the Active         Directory domain. You can additionally recover relationships for synced Active Directory         user and group objects and protect the Active Direct domain.<\/p>","href":"saas\/ms_entra_id_recovery_hybrid_env.html","attributes":{"data-id":"ms_entra_id_recovery_hybrid_env"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_recovery_hybrid_env-d27248e45590","next":"ms_entra_id_recovery_hybrid_env-d27248e45590"},{"title":"Microsoft Entra ID full tenant recovery","shortdesc":"<p class=\"shortdesc\">Using Microsoft Entra ID full tenant recovery, administrators can restore all objects         and relationships in a tenant from a previous state. You can specify objects to exclude from         recovery.<\/p>","href":"saas\/ms_entra_id_full_domain_recov.html","attributes":{"data-id":"ms_entra_id_full_domain_recov"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_full_domain_recov-d27248e45640","next":"ms_entra_id_full_domain_recov-d27248e45640"},{"title":"Microsoft Entra ID device protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Microsoft Entra ID devices by securing critical recovery         data against ransomware and accidental loss.<\/p>","href":"saas\/ms_entra_id_devices_protection.html","attributes":{"data-id":"ms_entra_id_devices_protection"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_devices_protection-d27248e45662","next":"ms_entra_id_devices_protection-d27248e45662"},{"title":"Downloading Microsoft Entra ID recovery details","shortdesc":"<p class=\"shortdesc\">Download a CSV file containing information about a completed Microsoft Entra ID         snapshot recovery. The information includes details about object IDs, object display names,         object types, and relationship recovery.<\/p>","href":"saas\/ms_entra_id_downloading_recovery_details.html","attributes":{"data-id":"ms_entra_id_downloading_recovery_details"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_downloading_recovery_details-d27248e45708","next":"ms_entra_id_downloading_recovery_details-d27248e45708"}]}};